+    /// Shared button-level cursor cleanup for custom-drawn Vesper controls.
+    /// `ButtonStyle.makeBody` only styles the label, so pointer behavior must
+    /// be applied to the Button view itself.
     private func vesperNativeButtonBehavior() -> some View {
         modifier(VesperNativeButtonBehavior())
