             .vesperNativeButtonBehavior()
@@ -184,7 +184,6 @@ private struct VesperNativeButtonBehavior: ViewModifier {

     func body(content: Content) -> some View {
         content
-            .focusEffectDisabled()
             .onHover { hovering in
                 if hovering {
                     guard !pushedArrowCursor else { return }
@@ -231,13 +230,9 @@ extension ButtonStyle where Self == VesperPopoverRowButtonStyle {
 }

 extension View {
-    /// Apply the popover-row button style and suppress the platform focus
-    /// effect at the Button level. `ButtonStyle.makeBody` can only modify
-    /// the label, so a `.focusEffectDisabled()` inside the style doesn't
-    /// reach the Button itself — the AppKit focus ring still draws around
-    /// the first row when the popover opens. Applying the modifier here,
-    /// at the Button view, suppresses it correctly. Use this anywhere a
-    /// popover row Button is composed so no caller forgets.
+    /// Apply the popover-row button style and shared cursor cleanup at the
