diff --git a/Tests/ButtonBehaviorLintTests.swift b/Tests/ButtonBehaviorLintTests.swift
index 433bbb19..d6d488cb 100644
--- a/Tests/ButtonBehaviorLintTests.swift
+++ b/Tests/ButtonBehaviorLintTests.swift
@@ -8,8 +8,8 @@ import Testing
 /// Invariant: custom Vesper button visuals are only applied through the
 /// `vesper*ButtonStyle()` view helpers in `ButtonStyles.swift`. Those helpers
 /// apply the visual style and the native macOS behavior contract at the Button
-/// level: no custom-control focus ring, arrow cursor on hover, and cursor-stack
-/// cleanup if the view disappears while hovered.
+/// level: arrow cursor on hover, native focus effects, and cursor-stack cleanup
+/// if the view disappears while hovered.
 @Suite("Button behavior lint")
 struct ButtonBehaviorLintTests {

@@ -28,8 +28,26 @@ struct ButtonBehaviorLintTests {
                 \(violation.relativePath):\(violation.line) applies a custom Vesper \
                 ButtonStyle directly. Use `vesperIconButtonStyle()`, \
                 `vesperGhostButtonStyle()`, `vesperSurfaceButtonStyle()`, or \
-                `vesperPopoverRowStyle(...)` so focus suppression and arrow-cursor \
-                behavior stay attached to the Button view itself.
+                `vesperPopoverRowStyle(...)` so shared cursor behavior stays \
+                attached to the Button view itself.
+                Match: \(violation.matchedText)
+                """
+            )
+        }
+    }
+
+    @Test("Custom button behavior preserves native focus effects")
+    func customButtonBehaviorPreservesNativeFocusEffects() throws {
+        let violations = try Self.scanSources { line in
+            line.contains("focusEffectDisabled")
+        }
+
+        for violation in violations where violation.relativePath.hasPrefix("Views/") || violation.relativePath.hasPrefix("Design/") {
+            Issue.record(
+                """
+                \(violation.relativePath):\(violation.line) disables native focus \
+                effects in SwiftUI chrome. Keep focus rings available for Full \
+                Keyboard Access unless a replacement focus affordance is provided.
                 Match: \(violation.matchedText)
                 """
             )
